import React, { useContext, useEffect } from 'react';
import PlanetsContext from '../contexts/PlanetsContext';
import Loading from './Loading';

function Table() {
  const { loading, planets, getPlanets } = useContext(PlanetsContext);

  useEffect(() => {
    getPlanets();
    // eslint-disable-next-line
  }, []);

  const headerTableInfos = Object.keys(planets[0]);

  return (
    loading ? <Loading /> : (
      <table>
        <thead>
          {
            headerTableInfos.map((info) => (
              <th key={ info }>
                { info }
              </th>
            ))
          }
        </thead>
        <tbody>
          {
            planets.map((planet) => (
              <td key={ planet }>
                { planet.name }
              </td>
            ))
          }
        </tbody>
      </table>

    )
  // <p>Requisição concluida</p>
  );
}

export default Table;
